def get_recipe(name: str) -> RecipeSpec:
    """Retrieve a recipe by name."""
    if name not in ALL_RECIPES:
        raise ValueError(f"Unknown recipe name: {name}")
    return ALL_RECIPES[name]

def list_recipes():
    """List all available recipe names."""
    return list(ALL_RECIPES.keys())

# PROFILE LOOKUP
# # ---------------------------------------------------------------------------

ALL_PROFILES = {
    "ChefA": CHEF_A,
    "ChefB": CHEF_B,
}


def get_profile(name: str) -> ProfileSpec:
    """Retrieve a profile by name."""
    if name not in ALL_PROFILES:
        raise ValueError(f"Unknown profile name: {name}")
    return ALL_PROFILES[name]

def list_profiles():
    """List all available profile names."""
    return list(ALL_PROFILES.keys())

if __name__ == "__main__":
    print("Available recipes:")
    for r in list_recipes():
        print(" -", r)

    recipe = get_recipe("SweetCurry")
    print("\nLoaded recipe:", recipe.name)
    for s, nxt in recipe.predecessors.items():
        print(f"  {s} -> {nxt}")
